  "title": "Codex CLI agent run structured output",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "schema_version",
    "record_type",
    "id",
    "agent_role",
    "agent_id",
    "mode",
    "started_at",
    "completed_at",
    "status",
    "scope",
    "canonical_write_policy",
    "execution",
    "inputs",
    "outputs",
    "quality_checks",
    "blocking_issues",
    "next_actions"
  ],
  "properties": {
    "schema_version": {
      "type": "string",
      "const": "1.0.0"
    },
    "record_type": {
      "type": "string",
      "const": "agent_run"
    },
    "id": {
      "type": "string",
      "pattern": "^[a-z0-9]+[a-z0-9._-]*$"
    },
    "agent_role": {
      "type": "string",
      "enum": [
        "triage_agent",
        "search_agent",
        "screening_agent",
        "dedupe_linker_agent",
